import{_ as o,o as i,c as d,ae as c}from"./chunks/framework.CyZiF_rV.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ru/api-changelog.md","filePath":"ru/api-changelog.md"}'),t={name:"ru/api-changelog.md"};function n(l,e,r,s,a,u){return i(),d("div",null,[...e[0]||(e[0]=[c(`<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/api-changelog.md" target="_blank" rel="noreferrer">api-changelog.md</a></p></blockquote><h2 id="изменения-в-api-2-0" tabindex="-1">Изменения в API 2.0 <a class="header-anchor" href="#изменения-в-api-2-0" aria-label="Permalink to &quot;Изменения в API 2.0&quot;">​</a></h2><h3 id="версия-2-2-0" tabindex="-1">Версия 2.2.0 <a class="header-anchor" href="#версия-2-2-0" aria-label="Permalink to &quot;Версия 2.2.0&quot;">​</a></h3><ul><li><p><strong>Разрешения</strong><br> Добавлен новый endpoint (POST <code>/permissions/query/entities/grants</code>), позволяющий получить список разрешений на обработку счетов в текущем контексте (возвращаемые разрешения: <code>InvoiceWrite</code>, <code>InvoiceRead</code> - предоставленные другим субъектом).</p></li><li><p><strong>Аутентификация</strong><br> Расширен ответ POST <code>/auth/challenge</code> свойством <code>clientIp</code>, возвращающим IP-адрес клиента, зарегистрированный в KSeF. Значение может быть напрямую использовано для построения <code>AuthorizationPolicy</code> в последующих шагах аутентификации.</p></li><li><p><strong>OpenAPI</strong></p><ul><li>Расширены ответы <code>401 Unauthorized</code> и <code>403 Forbidden</code> стандартизированным форматом ошибки &quot;Problem Details&quot; (<code>application/problem+json</code>). Добавлены схемы <code>UnauthorizedProblemDetails</code> и <code>ForbiddenProblemDetails</code>. <code>ForbiddenProblemDetails</code> предоставляет в том числе свойство <code>reasonCode</code> и опциональный объект <code>security</code> для дополнительной информации.</li><li>Восстановлены (касается только спецификации OpenAPI) <code>additionalProperties</code> для словарных полей: <code>InvoiceStatusInfo.extensions</code> и <code>PartUploadRequest.headers</code>.</li><li>Мелкие обновления описаний.</li></ul></li><li><p><strong>Экспорт пакета счетов (POST <code>/invoices/exports</code>).</strong><br> Исправлено генерирование файла <code>_metadata.json</code> в пакете экспорта - при большом количестве счетов файл мог быть ранее обрезан (некорректный JSON).</p></li></ul><h3 id="версия-2-1-2" tabindex="-1">Версия 2.1.2 <a class="header-anchor" href="#версия-2-1-2" aria-label="Permalink to &quot;Версия 2.1.2&quot;">​</a></h3><ul><li><p><strong>Отправка счетов</strong><br> Добавлена поддержка счетов RR (<a href="/ksef-docs/faktury/schemy/RR/schemat_RR(1)_v1-0E.xsd.html">схема_RR(1)_v1-0E</a>).</p></li><li><p><strong>Генерация нового токена (POST <code>/tokens</code>)</strong><br> В модели запроса (<code>GenerateTokenRequest</code>) расширено свойство <code>permissions</code> (enum <code>TokenPermissionType</code>) значением <code>Introspection</code>, позволяя предоставлять это разрешение при генерации токена.</p></li><li><p><strong>Экспорт пакета счетов (POST <code>/invoices/exports</code>). Получение списка метаданных счетов (POST <code>/invoices/query/metadata</code>)</strong><br> Исправлена интерпретация параметров <code>dateRange.from</code> / <code>dateRange.to</code>, указанных без смещения. Значения без временной зоны теперь однозначно интерпретируются согласно документации (местное время Europe/Warsaw).</p></li><li><p><strong>OpenAPI</strong><br> Удален <code>additionalProperties</code>: <code>false</code> в выбранных моделях. Изменение упорядочивает спецификацию и делает контракт более гибким - допускает возможность появления дополнительных свойств в запросах или ответах (например, в рамках расширений). Добавление нового свойства не рассматривается как нарушение контракта; клиенты API должны игнорировать неизвестные свойства.</p></li></ul><h3 id="версия-2-1-1" tabindex="-1">Версия 2.1.1 <a class="header-anchor" href="#версия-2-1-1" aria-label="Permalink to &quot;Версия 2.1.1&quot;">​</a></h3><ul><li><strong>Аутентификация</strong><ul><li><strong>Получение статуса аутентификации (GET <code>/auth/{referenceNumber}</code>)</strong> и <strong>Получение списка активных сессий (GET <code>/auth/sessions</code>)</strong><br> Дополнено определение <code>authenticationMethodInfo</code> - помечены свойства <code>category</code>, <code>code</code> и <code>displayName</code> как <code>required</code> в модели ответа.</li><li><strong>Аутентификация с использованием подписи XAdES (POST <code>/auth/xades-signature</code>)</strong><br> Добавлена возможность предварительного включения новых требований валидации XAdES на средах DEMO и PRD через заголовок: <code>X-KSeF-Feature</code>: <code>enforce-xades-compliance</code>.</li></ul></li></ul><h3 id="версия-2-1-0" tabindex="-1">Версия 2.1.0 <a class="header-anchor" href="#версия-2-1-0" aria-label="Permalink to &quot;Версия 2.1.0&quot;">​</a></h3><ul><li><p><strong>Аутентификация</strong></p><ul><li><p>Добавлена интеграция с Национальным узлом (login.gov.pl). Endpoint, используемый для этой интеграции, не является публично доступным (метод аутентификации предназначен исключительно для государственных приложений).</p></li><li><p><strong>Получение статуса аутентификации (GET <code>/auth/{referenceNumber}</code>)</strong> и <strong>Получение списка активных сессий (GET <code>/auth/sessions</code>)</strong></p><ul><li>Помечено в модели ответа свойство <code>authenticationMethod</code> как <code>deprecated</code>. Планируемое прекращение поддержки: <code>2026-11-16</code>. Для сохранения совместимости контракта в переходный период значение <code>TrustedProfile</code> включает как &quot;Доверенный профиль&quot;, так и аутентификации, осуществляемые через Национальный узел.</li><li>Добавлено новое свойство <code>authenticationMethodInfo</code> как гибкое описание метода аутентификации: <ul><li><code>category</code> - категория метода аутентификации (enum: <code>XadesSignature</code>, <code>NationalNode</code>, <code>Token</code>, <code>Other</code>),</li><li><code>code</code> - код метода аутентификации (string),</li><li><code>displayName</code> - название метода аутентификации для отображения пользователю (string).</li></ul></li><li>Расширены возможные значения поля details для статуса <code>460</code> (&quot;Аутентификация завершена неудачей из-за ошибки сертификата&quot;) о: &quot;Сертификат приостановлен&quot;.</li></ul></li><li><p><strong>Аутентификация с использованием подписи XAdES (POST <code>/auth/xades-signature</code>)</strong><br> Унифицирована и ужесточена валидация <a href="/ksef-docs/auth/podpis-xades.html">подписи XAdES</a> в процессе аутентификации, так чтобы принимались исключительно подписи, соответствующие требованиям профилей XAdES.<br> Новые требования уже действуют на среде TEST. На средах DEMO и PRD начнут действовать <strong>16 марта 2026</strong> (рекомендуется проверка интеграции на TEST перед этой датой).</p></li></ul></li><li><p><strong>Тестовые данные</strong><br> Добавлены новые endpointy:</p><ul><li>POST <code>/testdata/context/block</code> - &quot;Блокирует возможность аутентификации для указанного контекста. Аутентификация завершится ошибкой 480.&quot;,</li><li>POST <code>/testdata/context/unblock</code> - разблокирует возможность аутентификации для текущего контекста.</li></ul></li><li><p><strong>OpenAPI</strong><br> Мелкие обновления описаний.</p></li></ul><h3 id="версия-2-0-1" tabindex="-1">Версия 2.0.1 <a class="header-anchor" href="#версия-2-0-1" aria-label="Permalink to &quot;Версия 2.0.1&quot;">​</a></h3><ul><li><p><strong>Разрешения</strong></p><ul><li>Получение списка собственных разрешений (POST <code>/permissions/query/personal/grants</code>). <ul><li>Исправлена логика возврата списка &quot;Мои разрешения&quot; для владельца контекста - в результатах возвращаются также субъектные разрешения на выставление и просмотр счетов (<code>InvoiceWrite</code>, <code>InvoiceRead</code>), предоставленные <strong>без права</strong> дальнейшей передачи <code>canDelegate = false</code>. Ранее список возвращал только те, у которых есть право на дальнейшую передачу.</li><li>Добавлено описание для значения <code>InternalId</code> в <code>PersonalPermissionsContextIdentifierType</code>;</li><li>Обновлены ограничения длины <code>PersonalPermissionsContextIdentifier.value</code> (<code>maxLength</code> с 10 на 16).</li></ul></li><li>Исправлены примеры в документации OpenAPI для endpoints разрешений.</li></ul></li><li><p><strong>Получение счетов</strong><br> Уточнена валидация <code>dateRange</code> в <code>InvoiceQueryFilters</code>: диапазон 3 месяца считается корректным, если укладывается в три месяца по UTC или по польскому времени.</p></li><li><p><strong>Отправка счетов</strong></p><ul><li>Валидация номера NIP<br> Добавлена проверка контрольной суммы NIP для: <code>Podmiot1</code>, <code>Podmiot2</code>, <code>Podmiot3</code> и <code>PodmiotUpowazniony</code> (если присутствует) - касается только производственной среды.</li><li>Валидация NIP во внутреннем идентификаторе<br> Добавлена проверка контрольной суммы NIP в <code>InternalId</code> для <code>Podmiot3</code> (если идентификатор присутствует) - касается только производственной среды.</li><li>Обновление <a href="/ksef-docs/faktury/weryfikacja-faktury.html">документации</a>.</li></ul></li><li><p><strong>OpenAPI</strong><br> Мелкие обновления описаний.</p></li></ul><h3 id="версия-2-0-0" tabindex="-1">Версия 2.0.0 <a class="header-anchor" href="#версия-2-0-0" aria-label="Permalink to &quot;Версия 2.0.0&quot;">​</a></h3><ul><li><p><strong>UPO</strong><br> Согласно анонсу из RC6.0, с <code>2025-12-22</code> по умолчанию возвращается версия UPO v4-3.</p></li><li><p><strong>Статус сессии</strong> (GET <code>/sessions/{referenceNumber}</code>)</p><ul><li>Расширена модель ответа свойствами <code>dateCreated</code> (&quot;Дата создания сессии&quot;) и <code>dateUpdated</code> (&quot;Дата последней активности в рамках сессии&quot;).</li></ul></li><li><p><strong>Закрытие пакетной сессии (POST <code>/sessions/batch/{referenceNumber}/close</code>)</strong></p><ul><li>Добавлен код ошибки <code>21208</code> (&quot;Время ожидания запросов upload или finish было превышено&quot;).</li></ul></li><li><p><strong>Получение счета/UPO</strong></p><ul><li>Добавлен заголовок <code>x-ms-meta-hash</code> (хеш <code>SHA-256</code>, <code>Base64</code>) в ответах <code>200</code> для endpoints: <ul><li>GET <code>/invoices/ksef/{ksefNumber}</code>,</li><li>GET <code>/sessions/{referenceNumber}/invoices/ksef/{ksefNumber}/upo</code>,</li><li>GET <code>/sessions/{referenceNumber}/invoices/{invoiceReferenceNumber}/upo</code>,</li><li>GET <code>/sessions/{referenceNumber}/upo/{upoReferenceNumber}</code>.</li></ul></li></ul></li><li><p><strong>Получение статуса аутентификации</strong> (GET <code>/auth/{referenceNumber}</code>)</p><ul><li>Дополнена документация HTTP 400 (Bad Request) кодом ошибки <code>21304</code> (&quot;Отсутствие аутентификации&quot;) - операция аутентификации с номером {<code>referenceNumber</code>} не найдена.</li><li>Расширен статус <code>450</code> (&quot;Аутентификация завершена неудачей из-за неверного токена&quot;) дополнительной причиной: &quot;Неправильный авторизационный вызов&quot;.</li></ul></li><li><p><strong>Получение токенов доступа</strong> (POST <code>/auth/token/redeem</code>)<br> Дополнена документация HTTP 400 (Bad Request) кодами ошибок:</p><ul><li><code>21301</code> - &quot;Отсутствие авторизации&quot;: <ul><li>Токены для операции {<code>referenceNumber</code>} уже получены,</li><li>Статус аутентификации ({<code>operation.Status</code>}) не позволяет получить токены,</li><li>Токен KSeF был аннулирован.</li></ul></li><li><code>21304</code> - &quot;Отсутствие аутентификации&quot; - Операция аутентификации {<code>referenceNumber</code>} не найдена,</li><li><code>21308</code> - &quot;Попытка использования авторизационных методов умершего лица&quot;.</li></ul></li><li><p><strong>Обновление токена доступа</strong> (POST <code>/auth/token/refresh</code>)<br> Дополнена документация HTTP 400 (Bad Request) кодами ошибок:</p><ul><li><code>21301</code> - &quot;Отсутствие авторизации&quot;: <ul><li>Статус аутентификации ({<code>operation.Status</code>}) не позволяет получить токены,</li><li>Токен KSeF был аннулирован.</li></ul></li><li><code>21304</code> - &quot;Отсутствие аутентификации&quot; - Операция аутентификации {<code>referenceNumber</code>} не найдена,</li><li><code>21308</code> - &quot;Попытка использования авторизационных методов умершего лица&quot;.</li></ul></li><li><p><strong>Интерактивная отправка</strong> (POST <code>/sessions/online/{referenceNumber}/invoices</code>)<br> Дополнена документация кодов ошибок:</p><ul><li><code>21402</code> &quot;Неправильный размер файла&quot; - длина содержимого не соответствует размеру файла,</li><li><code>21403</code> &quot;Неправильный хеш файла&quot; - хеш содержимого не соответствует хешу файла.</li></ul></li><li><p><strong>Экспорт пакета счетов (POST <code>/invoices/exports</code>). Получение списка метаданных счетов (POST <code>/invoices/query/metadata</code>)</strong><br> Уменьшен максимальный допустимый диапазон <code>dateRange</code> с 2 лет до 3 месяцев.</p></li><li><p><strong>Разрешения</strong></p><ul><li>Добавлен атрибут <code>required</code> для свойства <code>subjectDetails</code> (&quot;Данные субъекта, которому предоставляются разрешения&quot;) во всех endpoints, предоставляющих разрешения (\`/permissions/.../grants).</li><li>Добавлен атрибут <code>required</code> для свойства <code>euEntityDetails</code> (&quot;Данные субъекта ЕС, в контексте которого предоставляются разрешения&quot;) в endpoint POST <code>/permissions/eu-entities/administration/grants</code> (&quot;Предоставление разрешений администратора субъекта ЕС&quot;).</li><li>Добавлено значение <code>PersonByFingerprintWithIdentifier</code> (&quot;Физическое лицо, использующее сертификат, не содержащий идентификатор NIP или PESEL, но имеющее NIP или PESEL&quot;) к enum <code>EuEntityPermissionSubjectDetailsType</code> в endpoint POST <code>/permissions/eu-entities/administration/grants</code> (&quot;Предоставление разрешений администратора субъекта ЕС&quot;).</li><li>Изменен тип свойства <code>subjectEntityDetails</code> на <code>PermissionsSubjectEntityByIdentifierDetails</code> (&quot;Данные уполномоченного субъекта&quot;) в модели ответа в POST <code>/permissions/query/authorizations/grants</code> (&quot;Получение списка субъектных разрешений на обработку счетов&quot;).</li><li>Изменен тип свойства <code>subjectEntityDetails</code> на <code>PermissionsSubjectEntityByFingerprintDetails</code> (&quot;Данные уполномоченного субъекта&quot;) в модели ответа в POST <code>/permissions/query/eu-entities/grants</code> (&quot;Получение списка разрешений администраторов или представителей субъектов ЕС, уполномоченных на самовыставление&quot;).</li><li>Изменен тип свойства <code>subjectPersonDetails</code> на <code>PermissionsSubjectPersonByFingerprintDetails</code> (&quot;Данные уполномоченного лица&quot;) в модели ответа в POST <code>/permissions/query/eu-entities/grants</code> (&quot;Получение списка разрешений администраторов или представителей субъектов ЕС, уполномоченных на самовыставление&quot;).</li><li>Введена валидация контрольной суммы для идентификатора <code>InternalId</code> в POST <code>/permissions/subunits/grants</code> (&quot;Предоставление разрешений администратора подчиненного субъекта&quot;).</li><li>Уточнены описания свойств.</li></ul></li><li><p><strong>OpenAPI</strong></p><ul><li>Дополнена документация ответа <code>429</code> возвращаемым заголовком <code>Retry-After</code> и содержанием ответа <code>TooManyRequestsResponse</code>.</li><li>Уточнены описания свойств типа <code>byte</code> - значения передаются как двоичные данные, закодированные в формате <code>Base64</code>.</li><li>Исправлены опечатки в спецификации.</li></ul></li></ul><h3 id="версия-2-0-0-rc6-1" tabindex="-1">Версия 2.0.0 RC6.1 <a class="header-anchor" href="#версия-2-0-0-rc6-1" aria-label="Permalink to &quot;Версия 2.0.0 RC6.1&quot;">​</a></h3><ul><li><p><strong>Новая адресация сред</strong><br> Предоставление новых адресов. Изменения в разделе <a href="./srodowiska.html">среды KSeF API 2.0</a>.</p></li><li><p><strong>Аутентификация - получение статуса (GET <code>/auth/{referenceNumber}</code>)</strong><br> Добавлен код <code>480</code> - Аутентификация заблокирована: &quot;Подозрение на инцидент безопасности. Свяжитесь с Министерством финансов через форму обращения.&quot;</p></li><li><p><strong>Разрешения</strong></p><ul><li>Расширены правила доступа для операций сессии (GET/POST <code>/sessions/...</code>): в список принимаемых разрешений добавлено <code>EnforcementOperations</code> (исполнительный орган).</li><li>Добавлены ограничения длины для свойств типа string: <code>minLength</code> и <code>maxLength</code>.</li><li>Добавлен <code>id</code> (<code>Asc</code>) как второй ключ сортировки в метаданных <code>x-sort</code> для запросов поиска разрешений. Порядок по умолчанию: <code>dateCreated</code> (<code>Desc</code>), затем <code>id</code> (<code>Asc</code>) - порядковое изменение, повышающее детерминированность пагинации.</li><li>Добавлена валидация свойства <code>IdDocument.country</code> в endpoint POST <code>/permissions/persons/grants</code> (&quot;Предоставление физическим лицам разрешений на работу в KSeF&quot;) - требуется соответствие <strong>ISO 3166-1 alpha-2</strong> (например, <code>PL</code>, <code>DE</code>, <code>US</code>).</li><li>&quot;Получение списка разрешений администраторов или представителей субъектов ЕС, уполномоченных на самовыставление&quot; (POST <code>/permissions/query/eu-entities/grants</code>): <ul><li>удалена валидация pattern (regex) и уточнено описание свойства <code>EuEntityPermissionsQueryRequest.authorizedFingerprintIdentifier</code>.</li><li>уточнено описание свойства <code>EuEntityPermissionsQueryRequest.vatUeIdentifier</code>.</li></ul></li></ul></li><li><p><strong>Интерактивная сессия</strong><br> Добавлены новые коды ошибок для POST <code>/sessions/online/{referenceNumber}/invoices</code> (&quot;Отправка счета&quot;):</p><ul><li><code>21166</code> - Техническая коррекция недоступна.</li><li><code>21167</code> - Статус счета не позволяет техническую коррекцию.</li></ul></li><li><p><strong>Лимиты API</strong></p><ul><li>Увеличен часовой лимит для группы <code>invoiceStatus</code> (получение статуса счета из сессии) с 720 до 1200 req/h: <ul><li>GET /sessions/{referenceNumber}/invoices/{invoiceReferenceNumber}.</li></ul></li><li>Увеличен часовой лимит для группы <code>sessionMisc</code> (ресурсы GET <code>/sessions/*</code>) с 720 до 1200 req/h: <ul><li>GET <code>/sessions/{referenceNumber}</code>,</li><li>GET <code>/sessions/{referenceNumber}/invoices/ksef/{ksefNumber}/upo</code>,</li><li>GET <code>/sessions/{referenceNumber}/invoices/{invoiceReferenceNumber}/upo</code>,</li><li>GET <code>/sessions/{referenceNumber}/upo/{upoReferenceNumber}</code>.</li></ul></li><li>Уменьшен часовой лимит для группы <code>batchSession</code> (открытие/закрытие пакетной сессии) с 120 до 60 req/h: <ul><li>POST <code>/sessions/batch</code>,</li><li>POST <code>/sessions/batch/{referenceNumber}/close</code>.</li></ul></li><li>Увеличены лимиты для endpoint <code>/invoices/exports/{referenceNumber}</code> (&quot;Получение статуса экспорта пакета счетов&quot;) путем добавления новой группы <code>invoiceExportStatus</code> с параметрами: 10 req/s, 60 req/min, 600 req/h.</li></ul></li><li><p><strong>Открытие пакетной сессии (POST <code>/sessions/batch</code>)</strong><br> Удалено из модели <code>BatchFilePartInfo</code> свойство <code>fileName</code> (ранее помеченное как deprecated; x-removal-date: 2025-12-07).</p></li><li><p><strong>Инициализация аутентификации (POST <code>/auth/challenge</code>)</strong><br> Добавлено свойство <code>timestampMs</code> (int64) в модели ответа - время генерации challenge в миллисекундах с 1.01.1970 (Unix).</p></li><li><p><strong>Тестовые данные</strong></p><ul><li>Уточнен тип свойства <code>expectedEndDate</code>: format: <code>date</code> в (POST <code>/testdata/attachment/revoke</code>).</li><li>Удалено значение <code>Token</code> из enum <code>SubjectIdentifierType</code> в endpoint POST <code>/testdata/limits/subject/certificate</code>. Значение не использовалось: в KSeF субъект не может быть &quot;токеном&quot; - идентичность всегда происходит от <code>NIP/PESEL</code> или отпечатка сертификата, который несет идентичность субъекта, который его создал.</li></ul></li><li><p><strong>OpenAPI</strong><br> Увеличено максимальное значение <code>pageSize</code> с 500 до 1000 для endpoints:</p><ul><li>GET <code>/sessions</code></li><li>GET <code>/sessions/{referenceNumber}/invoices</code></li><li>GET <code>/sessions/{referenceNumber}/invoices/failed</code></li></ul></li></ul><h3 id="версия-2-0-0-rc6-0" tabindex="-1">Версия 2.0.0 RC6.0 <a class="header-anchor" href="#версия-2-0-0-rc6-0" aria-label="Permalink to &quot;Версия 2.0.0 RC6.0&quot;">​</a></h3><ul><li><p><strong>Лимиты API</strong></p><ul><li>На среде <strong>TE</strong> (тестовая) включена и определена политика <a href="./limity/limity-api.html">лимитов api</a> со значениями в 10 раз выше, чем на <strong>PRD</strong>; подробности: <a href="/ksef-docs/limity/limity-api.html#limity-na-środowiskach">&quot;Лимиты на средах&quot;</a>.</li><li>На среде <strong>TR</strong> (DEMO) включены <a href="./limity/limity-api.html">лимиты api</a> со значениями, идентичными <strong>PRD</strong>. Значения реплицируются с продакшна; подробности: <a href="/ksef-docs/limity/limity-api.html#limity-na-środowiskach">&quot;Лимиты на средах&quot;</a>.</li><li>Добавлен endpoint POST <code>/testdata/rate-limits/production</code> - устанавливает в текущем контексте значения лимитов api согласно производственному профилю. Доступен только на среде <strong>TE</strong>.</li></ul></li><li><p><strong>Экспорт пакета счетов (POST <code>/invoices/exports</code>). Получение списка метаданных счетов (POST <code>/invoices/query/metadata</code>)</strong></p><ul><li>Добавлен документ <a href="./pobieranie-faktur/hwm.html">High Water Mark (HWM)</a>, описывающий механизм управления полнотой данных во времени.</li><li>Обновлен <a href="./pobieranie-faktur/przyrostowe-pobieranie-faktur.html">Инкрементальное получение счетов</a> рекомендациями по использованию механизма <code>HWM</code>.</li><li>Расширена модель ответа свойством <code>permanentStorageHwmDate</code> (string, date-time, nullable). Касается исключительно запросов с <code>dateType = PermanentStorage</code> и означает точку, ниже которой данные полные; для <code>dateType = Issue/Invoicing</code> - null.</li><li>Добавлено свойство <code>restrictToPermanentStorageHwmDate</code> (boolean, nullable) в объекте <code>dateRange</code>, которое включает механизм High Water Mark (<code>HWM</code>) и ограничивает диапазон дат до текущего значения <code>HWM</code>. Касается исключительно запросов с <code>dateType = PermanentStorage</code>. Применение параметра значительно снижает дубликаты между последовательными экспортами и обеспечивает согласованность во время длительной инкрементальной синхронизации.</li></ul></li><li><p><strong>UPO - обновление XSD до v4-3</strong></p><ul><li><p>Изменен паттерн (<code>pattern</code>) элемента <code>NumerKSeFDokumentu</code>, чтобы допускать также номера KSeF, генерируемые для счетов из KSeF 1.0 (36 символов).</p></li><li><p>Добавлен элемент <code>TrybWysylki</code> - режим отправки документа в KSeF: <code>Online</code> или <code>Offline</code>.</p></li><li><p>Изменено значение <code>NazwaStrukturyLogicznej</code> на формат: Schemat_{systemCode}_v{schemaVersion}.xsd (например, Schemat_FA(3)_v1-0E.xsd).</p></li><li><p>Изменено значение <code>NazwaPodmiotuPrzyjmujacego</code> на тестовых средах путем добавления суффикса с названием среды:</p><ul><li><code>TE</code>: Ministerstwo Finansów - środowisko testowe (TE),</li><li><code>TR</code>: Ministerstwo Finansów - środowisko przedprodukcyjne (TR).</li></ul><p><code>PRD</code>: без изменений - Ministerstwo Finansów.</p></li><li><p>В настоящее время по умолчанию возвращается UPO v4-2. Чтобы получить UPO v4-3, необходимо добавить заголовок: <code>X-KSeF-Feature: upo-v4-3</code> при открытии сессии (online/пакетной).</p></li><li><p>С <code>2025-12-22</code> версией по умолчанию будет UPO v4-3.</p></li><li><p>XSD UPO v4-3: <a href="/ksef-docs/faktury/upo/schemy/upo-v4-3.xsd.html">schema</a>.</p></li></ul></li><li><p><strong>Статус сессии</strong> (GET <code>/sessions/{referenceNumber}</code>)<br> Уточнено описание кода <code>440</code> - Сессия отменена: возможные причины - &quot;Превышено время отправки&quot; или &quot;Счета не переданы&quot;.</p></li><li><p><strong>Статус счета</strong> (GET <code>/sessions/{referenceNumber}/invoices/{invoiceReferenceNumber}</code>)<br> Добавлен тип <code>InvoiceStatusInfo</code> (расширяет <code>StatusInfo</code>) с полем <code>extensions</code> - объектом со структурированными деталями статуса. Поле <code>details</code> остается без изменений. Пример (дубликат счета):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">440</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Duplikat faktury&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;Duplikat faktury. Faktura o numerze KSeF: 5265877635-20250626-010080DD2B5E-26 została już prawidłowo przesłana do systemu w sesji: 20250626-SO-2F14610000-242991F8C9-B4&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;extensions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;originalSessionReferenceNumber&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;20250626-SO-2F14610000-242991F8C9-B4&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;originalKsefNumber&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;5265877635-20250626-010080DD2B5E-26&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li><li><p><strong>Разрешения</strong><br> Добавлено свойство <code>subjectDetails</code> - &quot;Данные субъекта, которому предоставляются разрешения&quot; ко всем endpoints, предоставляющим разрешения (/permissions/.../grants). В RC6.0 поле опционально; с 2025-12-19 будет обязательным.</p></li><li><p><strong>Поиск предоставленных разрешений</strong> (POST <code>/permissions/query/authorizations/grants</code>)<br> Расширены правила доступа о <code>PefInvoiceWrite</code>.</p></li><li><p><strong>Тестовые данные - вложения (POST /testdata/attachment/revoke)</strong><br> Расширена модель запроса <code>AttachmentPermissionRevokeRequest</code> полем <code>expectedEndDate</code> (опционально) - дата отзыва согласия на отправку счетов с вложением.</p></li><li><p><strong>OpenAPI</strong></p><ul><li>Добавлен ответ HTTP <code>429</code> - &quot;Too Many Requests&quot; ко всем endpoints. В свойстве <code>description</code> этого ответа публикуется табличное представление лимитов (<code>req/s</code>, <code>req/min</code>, <code>req/h</code>) и названия группы лимитов, назначенной endpoint. Механизм и семантика <code>429</code> остаются совместимыми с описанием в документации <a href="/ksef-docs/limity/limity-api.html">лимитов</a>.</li><li>К каждому endpoint добавлены метаданные <code>x-rate-limits</code> со значениями лимитов (<code>req/s</code>, <code>req/min</code>, <code>req/h</code>).</li><li>Удалены явные свойства <code>exclusiveMaximum</code>: <code>false</code> и <code>exclusiveMinimum</code>: <code>false</code> из числовых определений (оставлены только minimum/maximum). Упорядочивающее изменение – без влияния на валидацию (в OpenAPI значения по умолчанию этих свойств равны <code>false</code>).</li><li>Добавлены ограничения длины для свойств типа string: <code>minLength</code>.</li><li>Удалены явные настройки <code>style</code>: <code>form</code> для параметров в in: query.</li><li>Изменен порядок значений enum <code>BuyerIdentifierType</code> (сейчас: <code>None</code>, <code>Other</code>, <code>Nip</code>, <code>VatUe</code>). Упорядочивающее изменение - без влияния на работу.</li><li>Исправлена опечатка в описании свойства <code>KsefNumber</code>.</li><li>Уточнен формат свойства <code>PublicKeyCertificate</code>, представляющего двоичные данные, закодированные в <code>Base64</code>, установлен format: <code>byte</code>.</li><li>Внесены мелкие языковые и пунктуационные коррекции в поля <code>description</code>.</li></ul></li></ul><h3 id="версия-2-0-0-rc5-7" tabindex="-1">Версия 2.0.0 RC5.7 <a class="header-anchor" href="#версия-2-0-0-rc5-7" aria-label="Permalink to &quot;Версия 2.0.0 RC5.7&quot;">​</a></h3><ul><li><p><strong>Открытие пакетной сессии (POST <code>/sessions/batch</code>)</strong><br> Помечено в модели запроса <code>BatchFilePartInfo.fileName</code> как <code>deprecated</code> (планируемое удаление: 2025-12-05).</p></li><li><p><strong>Статусы асинхронных операций</strong><br> Добавлен статус <code>550</code> - &quot;Операция была отменена системой&quot;. Описание: &quot;Обработка была прервана по внутренним причинам системы. Попробуйте снова.&quot;</p></li><li><p><strong>OpenAPI</strong></p><ul><li>Добавлены ограничения количества элементов в массиве: <code>minItems</code>, <code>maxItems</code>.</li><li>Добавлены ограничения длины для свойств типа string: <code>minLength</code> и <code>maxLength</code>.</li><li>Обновлены описания свойств (<code>invoiceMetadataAuthorizedSubject.role</code>, <code>invoiceMetadataBuyer</code>, <code>invoiceMetadataThirdSubject.role</code>, <code>buyerIdentifier</code>).</li><li>Обновлены regex patterns для <code>vatUeIdentifier</code>, <code>authorizedFingerprintIdentifier</code>, <code>internalId</code>, <code>nipVatUe</code>, <code>peppolId</code>.</li></ul></li></ul><h3 id="версия-2-0-0-rc5-6" tabindex="-1">Версия 2.0.0 RC5.6 <a class="header-anchor" href="#версия-2-0-0-rc5-6" aria-label="Permalink to &quot;Версия 2.0.0 RC5.6&quot;">​</a></h3><ul><li><p><strong>Получение статуса сессии (GET <code>/sessions/{referenceNumber}</code>)</strong><br> Добавлено в ответе поле <code>UpoPageResponse.downloadUrlExpirationDate</code> - дата и время истечения адреса получения UPO; после этого момента <code>downloadUrl</code> больше не активен.</p></li><li><p><strong>Получение списка метаданных сертификатов (POST <code>/certificates/query</code>)</strong><br> Расширен ответ (<code>CertificateListItem</code>) свойством <code>requestDate</code> - дата подачи заявления на сертификацию.</p></li><li><p><strong>Получение списка поставщиков услуг Peppol (GET <code>/peppol/query</code>)</strong></p><ul><li>Расширена модель ответа полем <code>dateCreated</code> - дата регистрации поставщика услуг Peppol в системе.</li><li>Помечены свойства <code>dateCreated</code>, <code>id</code>, <code>name</code> в модели ответа как всегда возвращаемые.</li><li>Определена схема <code>PeppolI</code> (string, 9 символов) и применена в <code>PeppolProvider</code>.</li></ul></li><li><p><strong>OpenAPI</strong></p><ul><li>Добавлены метаданные <code>x-sort</code> ко всем endpoints, возвращающим списки. В описаниях endpoints добавлен раздел Сортировка с порядком по умолчанию (например, &quot;requestDate (Desc)&quot;).</li><li>Добавлены ограничения длины для свойств типа string: <code>minLength</code> и <code>maxLength</code>.</li><li>Уточнен формат свойств, представляющих двоичные данные, закодированные в <code>Base64</code>: установлен format: <code>byte</code> (<code>encryptedInvoiceContent</code>, <code>encryptedSymmetricKey</code>, <code>initializationVector</code>, <code>encryptedToken</code>).</li><li>Определена общая схема <code>Sha256HashBase64</code> и применена ко всем свойствам, представляющим хеш <code>SHA-256</code> в <code>Base64</code> (включая <code>invoiceHash</code>).</li><li>Определена общая схема <code>ReferenceNumber</code> (string, длина 36) и применена ко всем параметрам и свойствам, представляющим номер операции асинхронной операции (в путях, запросах и ответах).</li><li>Определена общая схема <code>Nip</code> (string, 10 символов, regex pattern) и применена ко всем свойствам, представляющим NIP.</li><li>Определена схема <code>Pesel</code> (string, 11 символов, regex pattern) и применена в свойстве, представляющем PESEL.</li><li>Определена общая схема <code>KsefNumber</code> (string, 35-36 символов, regex pattern) и применена ко всем свойствам, представляющим номер KSeF.</li><li>Определена схема <code>Challenge</code> (string, 36 символов) и применена в <code>AuthenticationChallengeResponse</code>.<code>challenge</code>.</li><li>Определена общая схема <code>PermissionId</code> (string, 36 символов) и применена во всех местах: в параметрах и в свойствах ответов.</li><li>Добавлены регулярные выражения для выбранных текстовых полей.</li></ul></li></ul><h3 id="версия-2-0-0-rc5-5" tabindex="-1">Версия 2.0.0 RC5.5 <a class="header-anchor" href="#версия-2-0-0-rc5-5" aria-label="Permalink to &quot;Версия 2.0.0 RC5.5&quot;">​</a></h3><ul><li><p><strong>Получение текущих лимитов API (GET <code>/api/v2/rate-limits</code>)</strong><br> Добавлен endpoint, возвращающий эффективные лимиты вызовов API в структуре <code>perSecond</code>/<code>perMinute</code>/<code>perHour</code> для отдельных областей (включая <code>onlineSession</code>, <code>batchSession</code>, <code>invoiceSend</code>, <code>invoiceStatus</code>, <code>invoiceExport</code>, <code>invoiceDownload</code>, <code>other</code>).</p></li><li><p><strong>Статус счета в сессии</strong><br> Расширен ответ для GET <code>/sessions/{referenceNumber}/invoices</code> (&quot;Получение счетов сессии&quot;) и GET <code>/sessions/{referenceNumber}/invoices/{invoiceReferenceNumber}</code> (&quot;Получение статуса счета из сессии&quot;) свойствами: <code>upoDownloadUrlExpirationDate</code> - &quot;дата и время истечения адреса. После этой даты ссылка <code>UpoDownloadUrl</code> не будет активна&quot;. Расширено описание <code>upoDownloadUrl</code>.</p></li><li><p><strong>Удаление полей *InMib (изменение согласно анонсу из 5.3)</strong><br> Удалены свойства <code>maxInvoiceSizeInMib</code> и <code>maxInvoiceWithAttachmentSizeInMib</code>. Изменение касается:</p><ul><li>GET <code>/limits/context</code> – ответов (<code>onlineSession</code>, <code>batchSession</code>),</li><li>POST <code>/testdata/limits/context/session</code> – модели запроса (<code>onlineSession</code>, <code>batchSession</code>),</li><li>Моделей: <code>BatchSessionContextLimitsOverride</code>, <code>BatchSessionEffectiveContextLimits</code>, <code>OnlineSessionContextLimitsOverride</code>, <code>OnlineSessionEffectiveContextLimits</code>. Для указания размеров используются исключительно поля *InMB (1 MB = 1 000 000 B).</li></ul></li><li><p><strong>Удаление <code>operationReferenceNumber</code> (изменение согласно анонсу из 5.3)</strong><br> Удалено свойство <code>operationReferenceNumber</code> из модели ответа; единственным обязательным названием является <code>referenceNumber</code>. Изменение включает:</p><ul><li>GET <code>/invoices/exports/{referenceNumber}</code> - &quot;Статус экспорта пакета счетов&quot;,</li><li>POST <code>/permissions/operations/{referenceNumber}</code> - &quot;Получение статуса операции разрешений&quot;.</li></ul></li><li><p><strong>Экспорт пакета счетов (POST <code>/invoices/exports</code>)</strong></p><ul><li>Добавлен новый код ошибки: <code>21182</code> - &quot;Достигнут лимит выполняющихся экспортов. Для аутентифицированного субъекта в текущем контексте достигнут максимальный лимит {count} одновременных экспортов счетов. Попробуйте позже&quot;.</li><li>Расширена модель ответа свойством <code>packageExpirationDate</code>, указывающим дату истечения подготовленного пакета. После истечения этой даты пакет не будет доступен для загрузки.</li><li>Добавлен код ошибки <code>210</code> - &quot;Экспорт счетов истек и больше не доступен для загрузки&quot;.</li></ul></li><li><p><strong>Статус экспорта пакета счетов (GET <code>/invoices/exports/{referenceNumber}</code>)</strong><br> Уточнены описания полей ссылок на загрузку частей пакета:</p><ul><li><code>url</code> - &quot;URL-адрес, на который необходимо отправить запрос загрузки части пакета. Ссылка генерируется динамически в момент запроса статуса операции экспорта. Не подлежит лимитам API и не требует передачи токена доступа при загрузке&quot;.</li><li><code>expirationDate</code> - &quot;Дата и время истечения ссылки, позволяющей загрузить часть пакета. После истечения этого момента ссылка перестает быть активной&quot;.</li></ul></li><li><p><strong>Авторизация</strong></p><ul><li>Расширены правила доступа о <code>SubunitManage</code> для POST <code>/permissions/query/persons/grants</code>: операцию можно выполнить, если субъект имеет <code>CredentialsManage</code>, <code>CredentialsRead</code>, <code>SubunitManage</code>.</li><li>Предоставление разрешений косвенным способом (POST <code>/permissions/indirect/grants</code>) Обновлено описание свойства <code>targetIdentifier.description</code>: уточнено, что отсутствие идентификатора контекста означает предоставление косвенного разрешения общего типа.</li></ul></li><li><p><strong>OpenAPI</strong><br> Увеличено максимальное значение <code>pageSize</code> с 100 до 500 для endpoints:</p><ul><li>GET <code>/sessions</code></li><li>GET <code>/sessions/{referenceNumber}/invoices</code></li><li>GET <code>/sessions/{referenceNumber}/invoices/failed</code></li></ul></li></ul><h3 id="версия-2-0-0-rc5-4" tabindex="-1">Версия 2.0.0 RC5.4 <a class="header-anchor" href="#версия-2-0-0-rc5-4" aria-label="Permalink to &quot;Версия 2.0.0 RC5.4&quot;">​</a></h3><ul><li><p><strong>Получение списка метаданных счетов (POST /invoices/query/metadata)</strong></p><ul><li>Добавлен параметр <code>sortOrder</code>, позволяющий определить направление сортировки результатов.</li></ul></li><li><p><strong>Статус сессии</strong><br> Устранена ошибка, препятствующая заполнению этого свойства в ответах API, касающихся счетов (поле ранее не возвращалось). Значение заполняется асинхронно в момент постоянного сохранения и может быть временно null.</p></li><li><p><strong>Тестовые данные (только на тестовых средах)</strong></p><ul><li>Изменение лимитов API для текущего контекста (POST <code>testdata/rate-limits</code>)<br> Добавлен endpoint, позволяющий временно переопределить эффективные лимиты API для текущего контекста. Изменение подготавливает запуск симулятора лимитов на среде TE.</li><li>Восстановление лимитов по умолчанию (DELETE <code>/testdata/rate-limits</code>) Добавлен endpoint, восстанавливающий значения лимитов по умолчанию для текущего контекста.</li></ul></li><li><p><strong>OpenAPI</strong></p><ul><li>Уточнены определения массивов параметров в query; применен <code>style: form</code>. Множественные значения следует передавать через повтор параметра, например <code>?statuses=InProgress&amp;statuses=Succeeded</code>. Документационное изменение, без влияния на работу API.</li><li>Обновлены описания свойств (<code>partUploadRequests</code>, <code>encryptedSymmetricKey</code>, <code>initializationVector</code>).</li></ul></li></ul><h3 id="версия-2-0-0-rc5-3" tabindex="-1">Версия 2.0.0 RC5.3 <a class="header-anchor" href="#версия-2-0-0-rc5-3" aria-label="Permalink to &quot;Версия 2.0.0 RC5.3&quot;">​</a></h3><ul><li><p><strong>Экспорт пакета счетов (POST <code>/invoices/exports</code>)</strong><br> Добавлена возможность включения файла <code>_metadata.json</code> в пакет экспорта. Файл имеет форму объекта JSON с массивом <code>invoices</code>, содержащим объекты <code>InvoiceMetadata</code> (модель, возвращаемая POST <code>/invoices/query/metadata</code>). Включение (preview): в заголовок запроса нужно добавить <code>X-KSeF-Feature</code>: <code>include-metadata</code>. С 2025-10-27 изменяется поведение endpoint по умолчанию - пакет экспорта всегда будет содержать файл <code>_metadata.json</code> (заголовок не потребуется).</p></li><li><p><strong>Статус счета</strong></p><ul><li>В случае обработки с ошибкой, когда было возможно прочитать номер счета (например, код ошибки <code>440</code> - дубликат счета), ответ содержит свойство <code>invoiceNumber</code> с прочитанным номером.</li><li>Помечены свойства <code>invoiceHash</code>, <code>referenceNumber</code> в модели ответа как всегда возвращаемые.</li></ul></li><li><p><strong>Стандартизация единиц размера (MB, SI)</strong><br> Унифицирована запись лимитов в документации и API: значения представлены в MB (SI), где 1 MB = 1 000 000 B.</p></li><li><p><strong>Получение лимитов для текущего контекста (GET <code>/limits/context</code>)</strong><br> Добавлены в модели ответа <code>maxInvoiceSizeInMB</code>, <code>maxInvoiceWithAttachmentSizeInMB</code> для свойств <code>onlineSession</code> и <code>batchSession</code>. Свойства <code>maxInvoiceSizeInMib</code>, <code>maxInvoiceWithAttachmentSizeInMib</code> помечены как deprecated (планируемое удаление: 2025-10-27).</p></li><li><p><strong>Изменение лимитов сессии для текущего контекста (POST <code>/testdata/limits/context/session</code>)</strong><br> Добавлены в модели запроса <code>maxInvoiceSizeInMB</code>, <code>maxInvoiceWithAttachmentSizeInMB</code> для свойств <code>onlineSession</code> и <code>batchSession</code>. Свойства <code>maxInvoiceSizeInMib</code>, <code>maxInvoiceWithAttachmentSizeInMib</code> помечены как deprecated (планируемое удаление: 2025-10-27).</p></li><li><p><strong>Статус экспорта пакета счетов (GET <code>/invoices/exports/{referenceNumber}</code>)</strong><br> Изменение названия параметра пути с <code>operationReferenceNumber</code> на <code>referenceNumber</code>.<br> Изменение не влияет на HTTP контракт (путь и значение без изменений) и поведение endpoint.</p></li><li><p><strong>Разрешения</strong></p><ul><li>Обновлены описания endpoints и примеры endpoints из области permissions/*. Изменение касается исключительно документации (уточнение описаний, форматов и примеров); отсутствуют изменения в поведении API и контракте.</li><li>Изменение названия параметра пути с <code>operationReferenceNumber</code> на <code>referenceNumber</code> в &quot;Получение статуса операции&quot; (POST <code>/permissions/operations/{referenceNumber}</code>).<br> Изменение не влияет на HTTP контракт (путь и значение без изменений) и поведение endpoint.</li><li>&quot;Предоставление разрешений косвенным способом&quot; (POST <code>permissions/indirect/grants</code>)<br> Добавлена поддержка внутреннего идентификатора - расширено свойство <code>targetIdentifier</code> значением <code>InternalId</code>.</li><li>&quot;Получение списка собственных разрешений&quot; (POST <code>/permissions/query/personal/grants</code>) <ul><li>Расширено в модели запроса свойство <code>targetIdentifier</code> значением <code>InternalId</code> (возможность указания внутреннего идентификатора).</li><li>Удалено в модели ответа значение <code>PersonalPermissionScope.Owner</code>. Владельческие разрешения (предоставляемые через ZAW-FA или привязка NIP/PESEL) не возвращаются.</li></ul></li></ul></li><li><p><strong>Статус аутентификации (GET <code>/auth/{referenceNumber}</code>)</strong><br> Расширена таблица кодов ошибок о <code>470</code> - &quot;Аутентификация завершена неудачей&quot; с уточнением: &quot;Попытка использования авторизационных методов умершего лица&quot;.</p></li><li><p><strong>Обработка счетов PEF</strong><br> Изменены значения enum (<code>FormCode</code>):</p><ul><li><code>FA_PEF (3)</code> на <code>PEF (3)</code>,</li><li><code>FA_KOR_PEF (3)</code> на <code>PEF_KOR (3)</code>.</li></ul></li><li><p><strong>Генерация нового токена (POST <code>/tokens</code>)</strong></p><ul><li>В модели запроса (<code>GenerateTokenRequest</code>) помечены поля <code>description</code> и <code>permissions</code> как обязательные.</li><li>В модели ответа (<code>GenerateTokenResponse</code>) помечены поля <code>referenceNumber</code> и <code>token</code> как всегда возвращаемые.</li></ul></li><li><p><strong>Статус токена KSeF (GET /tokens/{referenceNumber})</strong></p><ul><li>Помечены свойства <code>authorIdentifier</code>, <code>contextIdentifier</code>, <code>dateCreated</code>, <code>description</code>, <code>referenceNumber</code>, <code>requestedPermissions</code>, <code>status</code> в модели ответа как всегда возвращаемые.</li></ul></li><li><p><strong>Получение списка сгенерированных токенов (GET /tokens)</strong></p><ul><li>Помечены свойства <code>authorIdentifier</code>, <code>contextIdentifier</code>, <code>dateCreated</code>, <code>description</code>, <code>referenceNumber</code>, <code>requestedPermissions</code>, <code>status</code> в модели ответа как всегда возвращаемые.</li></ul></li><li><p><strong>Тестовые данные - создание физического лица (POST <code>/testdata/person</code>)</strong><br> Расширен запрос свойством <code>isDeceased</code> (boolean), позволяя создать тестовое умершее лицо (например, для сценариев проверки кода статуса <code>470</code>).</p></li><li><p><strong>OpenAPI</strong></p><ul><li>Уточнены ограничения для свойств типа integer в requests путем добавления атрибутов <code>minimum</code> / <code>exclusiveMinimum</code>, <code>maximum</code> / <code>exclusiveMaximum</code>.</li><li>Расширен ответ полем <code>referenceNumber</code> (содержит то же значение, что и прежнее <code>operationReferenceNumber</code>). Помечено <code>operationReferenceNumber</code> как <code>deprecated</code> и будет удалено из ответа 2025-10-27; следует перейти на <code>referenceNumber</code>. Характер изменения: переходное переименование с сохранением совместимости (оба свойства возвращаются параллельно до даты удаления).<br> Касается endpoints: <ul><li>POST <code>/permissions/persons/grants</code>,</li><li>POST <code>/permissions/entities/grants</code>,</li><li>POST <code>/permissions/authorizations/grants</code>,</li><li>POST <code>/permissions/indirect/grants</code>,</li><li>POST <code>/permissions/subunits/grants</code>,</li><li>POST <code>/permissions/eu-entities/administration/grants</code>,</li><li>POST <code>/permissions/eu-entities/grants</code>,</li><li>DELETE <code>/permissions/common/grants/{permissionId}</code>,</li><li>DELETE <code>/permissions/authorizations/grants/{permissionId}</code>,</li><li>POST <code>/invoices/exports</code>.</li></ul></li><li>Удален атрибут <code>required</code> из свойства <code>pageSize</code> в запросе GET <code>/sessions</code> (&quot;Получение списка сессий&quot;).</li><li>Обновлены примеры (example) в определениях endpoints.</li></ul></li></ul><h3 id="версия-2-0-0-rc5-2" tabindex="-1">Версия 2.0.0 RC5.2 <a class="header-anchor" href="#версия-2-0-0-rc5-2" aria-label="Permalink to &quot;Версия 2.0.0 RC5.2&quot;">​</a></h3><ul><li><p><strong>Разрешения</strong></p><ul><li>&quot;Предоставление разрешений администратора подчиненного субъекта&quot; (POST <code>/permissions/subunits/grants</code>)<br> Добавлено свойство <code>subunitName</code> (&quot;Название подчиненного подразделения&quot;) в запросе. Поле обязательно, когда подчиненное подразделение идентифицируется внутренним идентификатором.</li><li>&quot;Получение списка разрешений администраторов подразделений и подчиненных субъектов&quot; (POST <code>/permissions/query/subunits/grants</code>)<br> Добавлено в ответе свойство <code>subunitName</code> (&quot;Название подчиненного подразделения&quot;).</li><li>&quot;Получение списка разрешений на работу в KSeF, предоставленных физическим лицам или субъектам&quot; (POST <code>permissions/query/persons/grants</code>)<br> Удалено из результатов разрешение типа <code>Owner</code>. Разрешение <code>Owner</code> присваивается системно физическому лицу и не подлежит предоставлению, поэтому не должно появляться в списке предоставленных разрешений.</li><li>&quot;Получение списка собственных разрешений&quot; (POST <code>/permissions/query/personal/grants</code>)<br> Расширен enum фильтра <code>PersonalPermissionType</code> значением <code>VatUeManage</code>.</li></ul></li><li><p><strong>Лимиты</strong></p><ul><li>Добавлены endpoints для проверки установленных лимитов (контекст, аутентифицированный субъект): <ul><li>GET <code>/limits/context</code></li><li>GET <code>/limits/subject</code></li></ul></li><li>Добавлены endpoints для управления лимитами (контекст, аутентифицированный субъект) в тестовой среде: <ul><li>POST/DELETE <code>/testdata/limits/context/session</code></li><li>POST/DELETE <code>/testdata/limits/subject/certificate</code></li></ul></li><li>Обновлены <a href="./limity/limity.html">Лимиты</a>.</li></ul></li><li><p><strong>Статус счета</strong><br> Добавлено свойство <code>invoicingMode</code> в модели ответа. Обновлена документация: <a href="./offline/automatyczne-okreslanie-trybu-offline.html">Автоматическое определение режима отправки offline</a>.</p></li><li><p><strong>OpenAPI</strong></p><ul><li>Уточнены ограничения для свойств типа integer в requests путем добавления атрибутов <code>minimum</code> / <code>exclusiveMinimum</code>, <code>maximum</code> / <code>exclusiveMaximum</code> и значений по умолчанию <code>default</code>.</li><li>Обновлены примеры (example) в определениях endpoints.</li><li>Уточнены описания endpoints.</li><li>Добавлен атрибут <code>required</code> для обязательных свойств в запросах и ответах.</li></ul></li></ul><h3 id="версия-2-0-0-rc5-1" tabindex="-1">Версия 2.0.0 RC5.1 <a class="header-anchor" href="#версия-2-0-0-rc5-1" aria-label="Permalink to &quot;Версия 2.0.0 RC5.1&quot;">​</a></h3><ul><li><p><strong>Получение списка метаданных сертификатов (POST /certificates/query)</strong><br> Изменено представление идентификатора субъекта с пары свойств <code>subjectIdentifier</code> + <code>subjectIdentifierType</code> на составной объект <code>subjectIdentifier</code> { <code>type</code>, <code>value</code> }.</p></li><li><p><strong>Получение списка метаданных счетов (POST /invoices/query/metadata)</strong></p><ul><li>Изменено представление выбранных идентификаторов с пар свойств тип + value на составные объекты { type, value }: <ul><li><code>invoiceMetadataBuyer.identifier</code> + <code>invoiceMetadataBuyer.identifierType</code> на составной объект <code>invoiceMetadataBuyerIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>invoiceMetadataThirdSubject.identifier</code> + <code>invoiceMetadataThirdSubject.identifierType</code> на составной объект <code>InvoiceMetadataThirdSubjectIdentifier</code> { <code>type</code>, <code>value</code> }.</li></ul></li><li>Удалены <code>obsoleted</code> свойства <code>Identitifer</code> из объектов <code>InvoiceMetadataSeller</code> и <code>InvoiceMetadataAuthorizedSubject</code>.</li><li>Изменено свойство <code>invoiceQuerySeller</code> на <code>sellerNip</code> в фильтре запроса.</li><li>Изменено свойство <code>invoiceQueryBuyer</code> на <code>invoiceQueryBuyerIdentifier</code> со свойствами { <code>type</code>, <code>value</code> } в фильтре запроса.</li></ul></li><li><p><strong>Разрешения</strong><br> Изменено представление выбранных идентификаторов с пар свойств тип + value на составные объекты { type, value }:</p><ul><li>&quot;Получение списка собственных разрешений&quot; (POST <code>/permissions/query/personal/grants</code>): <ul><li><code>contextIdentifier</code> + <code>contextIdentifierType</code> -&gt; <code>contextIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>authorizedIdentifier</code> + <code>authorizedIdentifierType</code> -&gt; <code>authorizedIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>targetIdentifier</code> + <code>targetIdentifierType</code> -&gt; <code>targetIdentifier</code> { type, value }.</li></ul></li><li>&quot;Получение списка разрешений на работу в KSeF, предоставленных физическим лицам или субъектам&quot; (POST <code>/permissions/query/persons/grants</code>), <ul><li><code>contextIdentifier</code> + <code>contextIdentifierType</code> -&gt; <code>contextIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>authorizedIdentifier</code> + <code>authorizedIdentifierType</code> -&gt; <code>authorizedIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>targetIdentifier</code> + <code>targetIdentifierType</code> -&gt; <code>targetIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>authorIdentifier</code> + <code>authorIdentifierType</code> -&gt; <code>authorIdentifier</code> { <code>type</code>, <code>value</code> }.</li></ul></li><li>&quot;Получение списка разрешений администраторов подразделений и подчиненных субъектов&quot; (POST <code>/permissions/query/subunits/grants</code>): <ul><li><code>authorizedIdentifier</code> + <code>authorizedIdentifierType</code> -&gt; <code>authorizedIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>subunitIdentifier</code> + <code>subunitIdentifierType</code> -&gt; <code>subunitIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>authorIdentifier</code> + <code>authorIdentifierType</code> -&gt; <code>authorIdentifier</code> { <code>type</code>, <code>value</code> }.</li></ul></li><li>&quot;Получение списка ролей субъекта&quot; (POST <code>/permissions/query/entities/roles</code>): <ul><li><code>parentEntityIdentifier</code> + <code>parentEntityIdentifierType</code> -&gt; <code>parentEntityIdentifier</code> { <code>type</code>, <code>value</code> }.</li></ul></li><li>&quot;Получение списка подчиненных субъектов&quot; (POST <code>/permissions/query/subordinate-entities/roles</code>): <ul><li><code>subordinateEntityIdentifier</code> + <code>subordinateEntityIdentifierType</code> -&gt; <code>subordinateEntityIdentifier</code> { <code>type</code>, <code>value</code> }.</li></ul></li><li>&quot;Получение списка субъектных разрешений на обработку счетов&quot; (POST <code>/permissions/query/authorizations/grants</code>): <ul><li><code>authorizedEntityIdentifier</code> + <code>authorizedEntityIdentifierType</code> -&gt; <code>authorizedEntityIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>authorizingEntityIdentifier</code> + <code>authorizingEntityIdentifierType</code> -&gt; <code>authorizingEntityIdentifier</code> { <code>type</code>, <code>value</code> },</li><li><code>authorIdentifier</code> + <code>authorIdentifierType</code> -&gt; <code>authorIdentifier</code> { <code>type</code>, <code>value</code> }</li></ul></li><li>&quot;Получение списка разрешений администраторов или представителей субъектов ЕС, уполномоченных на самовыставление&quot; (POST <code>/permissions/query/eu-entities/grants</code>): <ul><li><code>authorIdentifier</code> + <code>authorIdentifierType</code> -&gt; <code>authorIdentifier</code> { <code>type</code>, <code>value</code> }</li></ul></li></ul></li><li><p><strong>Предоставление разрешений администратора субъекта ЕС (POST permissions/eu-entities/administration/grants)</strong><br> Изменено название свойства в запросе с <code>subjectName</code> на <code>euEntityName</code>.</p></li><li><p><strong>Аутентификация с использованием токена KSeF</strong><br> Удалены избыточные значения enum <code>None</code>, <code>AllPartners</code> в свойстве <code>contextIdentifier.type</code> запроса POST <code>/auth/ksef-token</code>.</p></li><li><p><strong>Токены KSeF</strong></p><ul><li>Унифицирована модель ответа GET <code>/tokens</code>: свойства <code>authorIdentifier.type</code>, <code>authorIdentifier.value</code>, <code>contextIdentifier.type</code>, <code>contextIdentifier.value</code> всегда возвращаются (required, non-nullable),</li><li>Удалены избыточные значения enum <code>None</code>, <code>AllPartners</code> в свойствах <code>authorIdentifier.type</code> и <code>contextIdentifier.type</code> в модели ответа GET <code>/tokens</code> (&quot;Получение списка сгенерированных токенов&quot;).</li></ul></li><li><p><strong>Пакетная сессия</strong><br> Удален избыточный код ошибки <code>21401</code> - &quot;Документ не соответствует схеме (json)&quot;.</p></li><li><p><strong>Получение статуса сессии (GET /sessions/{referenceNumber})</strong></p><ul><li>Добавлен код ошибки <code>420</code> - &quot;Превышен лимит счетов в сессии&quot;.</li></ul></li><li><p><strong>Получение метаданных счетов (GET <code>/invoices/query/metadata</code>)</strong></p><ul><li>Добавлено в ответе (всегда возвращаемое) свойство <code>isTruncated</code> (boolean) – &quot;Определяет, был ли результат обрезан из-за превышения лимита количества счетов (10 000)&quot;,</li><li>Помечено свойство <code>amount.type</code> в фильтре запроса как обязательное.</li></ul></li><li><p><strong>Экспорт пакета счетов: задание (POST <code>/invoices/exports</code>)</strong></p><ul><li>Помечено свойство <code>operationReferenceNumber</code> в модели ответа как всегда возвращаемое,</li><li>Помечено свойство <code>amount.type</code> в фильтре запроса как обязательное.</li></ul></li><li><p><strong>Получение списка разрешений на работу в KSeF, предоставленных физическим лицам или субъектам (POST /permissions/query/persons/grants)</strong></p><ul><li>Добавлен <code>contextIdentifier</code> в фильтре запроса и в модели ответа.</li></ul></li><li><p><strong>OpenAPI</strong><br> Удален неиспользуемый <code>operationId</code> из спецификации. Упорядочивающее изменение.</p></li></ul><h3 id="версия-2-0-0-rc5" tabindex="-1">Версия 2.0.0 RC5 <a class="header-anchor" href="#версия-2-0-0-rc5" aria-label="Permalink to &quot;Версия 2.0.0 RC5&quot;">​</a></h3><ul><li><p><strong>Обработка счетов PEF и поставщиков услуг Peppol</strong></p><ul><li>Добавлена поддержка счетов <code>PEF</code>, отправляемых поставщиком услуг Peppol. Новые возможности не изменяют прежние поведения KSeF для других форматов, являются расширением API.</li><li>Введен новый тип контекста аутентификации: <code>PeppolId</code>, позволяющий работать в контексте поставщика услуг Peppol.</li><li>Автоматическая регистрация поставщика: при первой аутентификации поставщика услуг Peppol (с использованием выделенного сертификата) происходит его автоматическая регистрация в системе.</li><li>Добавлен endpoint GET <code>/peppol/query</code> (&quot;Список поставщиков услуг Peppol&quot;), возвращающий зарегистрированных поставщиков.</li><li>Обновлены правила доступа для открытия и закрытия сессии, отправка счетов требует разрешения <code>PefInvoiceWrite</code>.</li><li>Добавлены новые схемы счетов: <code>FA_PEF (3)</code>, <code>FA_KOR_PEF (3)</code>,</li><li>Расширен <code>ContextIdentifier</code> о <code>PeppolId</code> в xsd <code>AuthTokenRequest</code>.</li></ul></li><li><p><strong>UPO</strong></p><ul><li>Добавлен элемент <code>Uwierzytelnienie</code>, который упорядочивает данные из заголовка UPO и расширяет их дополнительной информацией; заменяет прежние <code>IdentyfikatorPodatkowyPodmiotu</code> и <code>SkrotZlozonejStruktury</code>.</li><li><code>Uwierzytelnienie</code> содержит: <ul><li><code>IdKontekstu</code> – идентификатор контекста аутентификации,</li><li>доказательство аутентификации (в зависимости от метода): <ul><li><code>NumerReferencyjnyTokenaKSeF</code> - идентификатор токена аутентификации в системе KSeF,</li><li><code>SkrotDokumentuUwierzytelniajacego</code> - значение функции хеша документа аутентификации в полученном системой виде (включая электронную подпись).</li></ul></li></ul></li><li>В элементе <code>Dokument</code> добавлены: <ul><li>NipSprzedawcy,</li><li>DataWystawieniaFaktury,</li><li>DataNadaniaNumeruKSeF.</li></ul></li><li>Унифицирована схема UPO. UPO для счета и для сессии используют общую схему upo-v4-2.xsd. Заменяет прежние upo-faktura-v3-0.xsd и upo-sesja-v4-1.</li></ul></li></ul>`,34)])])}const m=o(t,[["render",n]]);export{g as __pageData,m as default};
